                        <span class="badge" onclick="event.stopPropagation();app.openScoreAdjustmentModal('prospect',${a.id})" style="background:var(--primary);color:#fff;cursor:pointer;user-select:none;" title="Click to adjust score">\u2B50 ${a.score||0} pts (${fe(a.score||0)}) <i class="fas fa-pen" style="font-size:9px;opacity:.8;margin-left:2px;"></i></span>
